import { HelpFormatter } from './help-formatter.js';

export class ValidationHelper {
  /**
   * Validate enum parameter
   */
  static validateEnum(
    value: string,
    paramName: string,
    validOptions: string[],
    commandPath: string,
  ): void {
    if (!validOptions.includes(value)) {
      console.error(
