  private static readonly API_KEY_PATTERNS = [
    // Anthropic API keys
    /sk-ant-[a-zA-Z0-9_-]{95,}/gi,

    // OpenRouter API keys
    /sk-or-[a-zA-Z0-9_-]{32,}/gi,

    // Google/Gemini API keys
    /AIza[a-zA-Z0-9_-]{35}/gi,

    // Generic API keys
    /[a-zA-Z0-9_-]{20,}API[a-zA-Z0-9_-]{20,}/gi,

    // Bearer tokens
    /Bearer\s+[a-zA-Z0-9_\-\.]{20,}/gi,

